// Help entries for the Statistics and Machine Learning Toolbox, extracted from stats.ts.
// Keyed by function name; consumed via ToolboxModule.help (see tb/types.ts).
import type { HelpEntry } from './types';

export const HELP_STATS: Record<string, HelpEntry | string> = {
    ttest: { summary: 'Returns a test decision for the null hypothesis that the data in x comes from a normal distribution with mean equal to zero and unknown variance, using the one-sample t-test.', syntax: ['h = ttest(x)', 'h = ttest(x,y)', 'h = ttest(x,y,Name,Value)', 'h = ttest(x,m)'], seealso: ['ztest', 'ttest2', 'sampsizepwr'], description: ['h = ttest(x) returns a test decision for the null hypothesis that the data in x comes from a normal distribution with mean equal to zero and unknown variance, using the one-sample _t_ -test. The alternative hypothesis is that the population distribution does not have a mean equal to zero. The result h is 1 if the test rejects the null hypothesis at the 5% significance level, and 0 otherwise.', 'h = ttest(x,y) returns a test decision for the null hypothesis that the data in x – y comes from a normal distribution with mean equal to zero and unknown variance, using the paired-sample _t_ -test. The alternative hypothesis is that the mean of the data in x – y is not equal to zero.', 'h = ttest(x,y,Name,Value) returns a test decision for the paired- sample _t_ -test with additional options specified by one or more name-value pair arguments. For example, you can change the significance level or conduct a one-sided test.', 'h = ttest(x,m) returns a test decision for the null hypothesis that the data in x comes from a normal distribution with mean m and unknown variance. The alternative hypothesis is that the mean is not m.', 'h = ttest(x,m,Name,Value) returns a test decision for the one-sample _t_ -test with additional options specified by one or more name-value pair arguments. For example, you can change the significance level or conduct a one-sided test.'] },
    ranksum: { summary: 'Returns the p-value of a two-sided Wilcoxon rank sum test.', syntax: ['p = ranksum(x,y)', '[ ___ ] = ranksum(x,y,Name,Value)'], seealso: ['kruskalwallis', 'signrank', 'signtest', 'ttest2'], description: ['p = ranksum(x,y) returns the _p_ -value of a two-sided Wilcoxon rank sum test. ranksum tests the null hypothesis that data in x and y are samples from continuous distributions with equal medians, against the alternative that they are not. The test assumes that the two samples are independent. x and y can have different lengths.', 'This test is equivalent to a Mann-Whitney U-test.', '[p,h] = ranksum(x,y) also returns a logical value indicating the test decision. The result h = 1 indicates a rejection of the null hypothesis, and h = 0 indicates a failure to reject the null hypothesis at the 5% significance level.', '[p,h,stats] = ranksum(x,y) also returns the structure stats with information about the test statistic.', '[___] = ranksum(x,y,Name,Value) returns any of the output arguments in the previous syntaxes, for a rank sum test with additional options specified by one or more Name,Value pair arguments.'] },
    adtest: { summary: 'Returns a test decision for the null hypothesis that the data in vector x is from a population with a normal distribution, using the Anderson-Darling test.', syntax: ['h = adtest(x)', 'h = adtest(x,Name,Value)'], seealso: ['kstest', 'jbtest'], description: ['h = adtest(x) returns a test decision for the null hypothesis that the data in vector x is from a population with a normal distribution, using the Anderson-Darling test. The alternative hypothesis is that x is not from a population with a normal distribution. The result h is 1 if the test rejects the null hypothesis at the 5% significance level, or 0 otherwise.', 'h = adtest(x,Name,Value) returns a test decision for the Anderson- Darling test with additional options specified by one or more name-value pair arguments. For example, you can specify a null distribution other than normal, or select an alternative method for calculating the _p_ -value.', '[h,p] = adtest(___) also returns the _p_ -value, p, of the Anderson- Darling test, using any of the input arguments from the previous syntaxes.', '[h,p,adstat,cv] = adtest(___) also returns the test statistic, adstat, and the critical value, cv, for the Anderson-Darling test.'] },
    ansaribradley: { summary: 'Returns a test decision for the null hypothesis that the data in vectors x and y comes from the same distribution, using the Ansari-Bradley test.', syntax: ['h = ansaribradley(x,y)', 'h = ansaribradley(x,y,Name,Value)'], seealso: ['vartest2', 'vartestn', 'ttest2'], description: ['h = ansaribradley(x,y) returns a test decision for the null hypothesis that the data in vectors x and y comes from the same distribution, using the Ansari-Bradley test. The alternative hypothesis is that the data in x and y comes from distributions with the same median and shape but different dispersions (e.g., variances). The result h is 1 if the test rejects the null hypothesis at the 5% significance level, or 0 otherwise.', 'h = ansaribradley(x,y,Name,Value) returns a test decision for the Ansari-Bradley test with additional options specified by one or more name- value pair arguments. For example, you can change the significance level, conduct a one-sided test, or use a normal approximation to calculate the value of the test statistic.', '[h,p] = ansaribradley(___) also returns the _p_ -value, p, of the test, using any of the input arguments in the previous syntaxes.', '[h,p,stats] = ansaribradley(___) also returns the structure stats containing information about the test statistic.'] },
    kstest2: { summary: 'Returns a test decision for the null hypothesis that the data in vectors x1 and x2 are from the same continuous distribution, using the two-sample Kolmogorov-Smirnov test.', syntax: ['h = kstest2(x1,x2)', '[h,p] = kstest2(x1,x2)', '[h,p,ks2stat] = kstest2(x1,x2)', '[ ___ ] = kstest2(x1,x2,Name,Value)'], seealso: ['kstest', 'adtest', 'lillietest'], description: ['h = kstest2(x1,x2) returns a test decision for the null hypothesis that the data in vectors x1 and x2 are from the same continuous distribution, using the two-sample Kolmogorov-Smirnov test. The alternative hypothesis is that x1 and x2 are from different continuous distributions. The result h is 1 if the test rejects the null hypothesis at the 5% significance level, and 0 otherwise.', 'h = kstest2(x1,x2,Name,Value) returns a test decision for a two- sample Kolmogorov-Smirnov test with additional options specified by one or more name-value pair arguments. For example, you can change the significance level or conduct a one-sided test.', '[h,p] = kstest2(___) also returns the asymptotic _p_ -value p, using any of the input arguments from the previous syntaxes.', '[h,p,ks2stat] = kstest2(___) also returns the test statistic ks2stat.'] },
    signtest: { summary: 'Returns the p-value of a two-sided sign test for the null hypothesis that data in x has zero median (or that x and y have equal medians).', syntax: ['p = signtest(x)', 'p = signtest(x,y)', '[p,h,stats] = signtest( ___ )'], seealso: ['signrank', 'ranksum', 'ttest'], description: ['p = signtest(x) returns the _p_ -value for a two-sided sign test.', 'signtest tests the hypothesis that data in x has a continuous distribution with zero median against the alternative that the distribution does not have zero median at the 5% significance level.', 'p = signtest(x,y) returns the _p_ -value of a two-sided sign test. Here,signtest tests for the hypothesis that the data in x – y has a distribution with zero median against the alternative that the distribution does not have zero median. Note that a hypothesis of zero median for x – y is not equivalent to a hypothesis of equal median for x and y.', 'p = signtest(x,y,Name,Value) returns the _p_ -value for the sign test with additional options specified by one or more Name,Value pair arguments.', '[p,h] = signtest(___) also returns a logical value indicating the test decision. The value h = 1 indicates a rejection of the null hypothesis, and h = 0 indicates a failure to reject the null hypothesis at the 5% significance level. You can use any of the input arguments in the previous syntaxes.'] },
    friedman: { summary: "Returns the p-value for a balanced two-way ANOVA by ranks (Friedman's test) for the data in matrix x.", syntax: ['p = friedman(x,reps)', '[p,tbl] = friedman(x,reps)', '[p,tbl,stats] = friedman( ___ )'], seealso: ['anova2', 'kruskalwallis', 'multcompare'], description: ['p = friedman(x,reps) returns the _p_ -value for the nonparametric Friedman\'s test to compare column effects in a two-way layout. friedman tests the null hypothesis that the column effects are all the same against the alternative that they are not all the same. Friedman\'s test provides an analysis that is similar to a two-way ANOVA without interactions. For more information, see Friedman’s Test.', 'p = friedman(x,reps,displayopt) enables the ANOVA table display when displayopt is \'on\' (default) and suppresses the display when displayopt is \'off\'.', '[p,tbl] = friedman(___) returns the ANOVA table (including column and row labels) in cell array tbl.', '[p,tbl,stats] = friedman(___) also returns a structure stats that you can use to perform a follow-up multiple comparison test.'] },
    vartestn: { summary: 'Returns the p-value for the test of the null hypothesis that the columns of the data matrix x come from normal distributions with the same variance.', syntax: ['p = vartestn(x)', 'p = vartestn(x,group)', 'p = vartestn( ___ ,Name,Value)'], seealso: ['vartest', 'vartest2', 'ansaribradley'], description: ['vartestn(x) returns a summary table of statistics and a box plot for a Bartlett test of the null hypothesis that the columns of data vector x come from normal distributions with the same variance. The alternative hypothesis is that not all columns of data have the same variance.', 'vartestn(x,Name,Value) returns a summary table of statistics and a box plot for a test of unequal variances with additional options specified by one or more name-value pair arguments. For example, you can specify a different type of hypothesis test or change the display settings for the test results.', 'vartestn(x,group) returns a summary table of statistics and a box plot for a Bartlett test of the null hypothesis that the data in each categorical group comes from normal distributions with the same variance. The alternative hypothesis is that not all groups have the same variance.', 'vartestn(x,group,Name,Value) returns a summary table of statistics and a box plot for a test of unequal variances with additional options specified by one or more name-value pair arguments. For example, you can specify a different type of hypothesis test or change the display settings for the test results.', 'p = vartestn(___) also returns the _p_ -value of the test, p, using any of the input arguments in the previous syntaxes.'] },
    copulapdf: { summary: 'Returns the probability density of the copula family, evaluated at the points in the n-by-d matrix u.', syntax: ['y = copulapdf(family,u,rho)', "y = copulapdf('t',u,rho,nu)", 'y = copulapdf(family,u,alpha)'], seealso: ['copulacdf', 'copulastat', 'copulaparam'], description: ['y = copulapdf(\'Gaussian\',u,rho) returns the probability density of the Gaussian copula with linear correlation parameters, rho, evaluated at the points in u.', 'y = copulapdf(\'t\',u,rho,nu) returns the probability density of the _t_ copula with linear correlation parameters, rho, and degrees of freedom parameter, nu, evaluated at the points in u.', 'y = copulapdf(family,u,alpha) returns the probability density of the bivariate Archimedean copula of the type specified by family, with scalar parameter, alpha, evaluated at the points in u.'] },
    copulacdf: { summary: 'Returns the cumulative probability of the copula family, evaluated at the points in the n-by-d matrix u.', syntax: ['p = copulacdf(family,u,rho)', "p = copulacdf('t',u,rho,nu)", 'p = copulacdf(family,u,alpha)'], seealso: ['copulapdf', 'copulastat', 'copularnd'], description: ['y = copulacdf(\'Gaussian\',u,rho) returns the cumulative probability of the Gaussian copula, with linear correlation parameters rho evaluated at the points in u.', 'y = copulacdf(\'t\',u,rho,nu) returns the cumulative probability of the _t_ copula, with linear correlation parameters, rho, and degrees of freedom parameter nu evaluated at the points in u.', 'y = copulacdf(family,u,alpha) returns the cumulative probability of the bivariate Archimedean copula of the type specified by family, with scalar parameter alpha evaluated at the points in u.'] },
    mvncdf: { summary: 'Returns the cumulative probability of the multivariate normal distribution with zero mean and identity covariance matrix, evaluated at each row of X.', syntax: ['y = mvncdf(X)', 'y = mvncdf(X,mu,Sigma)', 'y = mvncdf(xl,xu,mu,Sigma)'], seealso: ['mvnpdf', 'mvncdf', 'normcdf', 'mvtcdf'], description: ['p = mvncdf(X) returns the cumulative distribution function (cdf) of the multivariate normal distribution with zero mean and identity covariance matrix, evaluated at each row of X. For more information, see Multivariate Normal Distribution.', 'p = mvncdf(X,mu,Sigma) returns the cdf of the multivariate normal distribution with mean mu and covariance Sigma, evaluated at each row of X.', 'Specify [] for mu to use its default value of zero when you want to specify only Sigma.', 'p = mvncdf(xl,xu,mu,Sigma) returns the multivariate normal cdf evaluated over the multidimensional rectangle with lower and upper limits defined by xl and xu, respectively.', 'p = mvncdf(___,options) specifies control parameters for the numerical integration used to compute p, using any of the input argument combinations in the previous syntaxes. Create the options argument using the statset function with any combination of the parameters \'TolFun\', \'MaxFunEvals\', and \'Display\'.'] },
    mvtcdf: { summary: 'Returns the cumulative probability of the multivariate Student t distribution with correlation matrix C and nu degrees of freedom, evaluated at each row of X.', syntax: ['y = mvtcdf(X,C,nu)', 'y = mvtcdf(xl,xu,C,nu)'], seealso: ['mvncdf', 'mvtpdf', 'tcdf'], description: ['p = mvtcdf(X,C,nu) returns the cumulative distribution function (cdf) of the multivariate _t_ distribution with the correlation parameters C and degrees of freedom nu, evaluated at each row of X.', 'p = mvtcdf(xl,xu,C,nu) returns the multivariate cdf evaluated over the multidimensional rectangle with lower and upper limits defined by xl and xu, respectively.', 'p = mvtcdf(___,options) specifies control parameter options for the numerical integration used to compute p, using any of the input argument combinations in the previous syntaxes. Create the options argument using the statset function.', '[p,err] = mvtcdf(___) additionally returns an estimate of the error in p. For more information, see Algorithms.'] },
    sampsizepwr: { summary: 'Sampsizepwr computes the sample size, power, or alternative parameter value for a hypothesis test, given the other two values.', syntax: ['nout = sampsizepwr(testtype,p0,p1)', 'nout = sampsizepwr(testtype,p0,p1,pwr)', 'pwrout = sampsizepwr(testtype,p0,p1,[],n)', 'p1out = sampsizepwr(testtype,p0,[],pwr,n)'], seealso: ['vartest', 'ttest', 'ttest2', 'ztest', 'binocdf'], description: ['sampsizepwr computes the sample size, power, or alternative parameter value for a hypothesis test, given the other two values. For example, you can compute the sample size required to obtain a particular power for a hypothesis test, given the parameter value of the alternative hypothesis.', 'nout = sampsizepwr(testtype,p0,p1) returns the sample size, nout, required for a two-sided test of the type specified by testtype to have a power (probability of rejecting the null hypothesis when the alternative hypothesis is true) of 0.90 when the significance level (probability of rejecting the null hypothesis when the null hypothesis is true) is 0.05. p0 specifies parameter values under the null hypothesis. p1 specifies the value, or an array of values, of the single parameter being tested under the alternative hypothesis.', 'nout = sampsizepwr(testtype,p0,p1,pwr) returns the sample size, nout, that corresponds to the specified power, pwr, and the parameter value under the alternative hypothesis, p1.', 'pwrout = sampsizepwr(testtype,p0,p1,[],n) returns the power achieved for a sample size of n when the true parameter value is p1.', 'p1out = sampsizepwr(testtype,p0,[],pwr,n) returns the parameter value detectable with the specified sample size, n, and the specified power, pwr.'] },
    normpdf: { summary: 'Returns the probability density function (pdf) of the standard normal distribution, evaluated at the values in x.', syntax: ['y = normpdf(x)', 'y = normpdf(x,mu)', 'y = normpdf(x,mu,sigma)'], seealso: ['pdf', 'normcdf', 'norminv', 'normrnd', 'mvnpdf'], description: ['y = normpdf(x) returns the probability density function (pdf) of the standard normal distribution, evaluated at the values in x.', 'y = normpdf(x,mu) returns the pdf of the normal distribution with mean mu and the unit standard deviation, evaluated at the values in x.', 'y = normpdf(x,mu,sigma) returns the pdf of the normal distribution with mean mu and standard deviation sigma, evaluated at the values in x.'] },
    tpdf: "Student's t probability density function", tcdf: "Student's t cumulative distribution function", tinv: "Student's t inverse cumulative distribution function",
    chi2pdf: { summary: 'Returns the probability density function (pdf) of the chi-square distribution with nu degrees of freedom, evaluated at the values in x.', syntax: ['y = chi2pdf(x,nu)'], seealso: ['pdf', 'chi2cdf', 'chi2inv', 'chi2stat', 'chi2rnd'], description: ['y = chi2pdf(x,nu) returns the probability density function (pdf) of the chi-square distribution with nu degrees of freedom, evaluated at the values in x.'] },
    gampdf: { summary: 'Returns the probability density function (pdf) of the standard gamma distribution with the shape parameter a, evaluated at the values in x.', syntax: ['y = gampdf(x,a)', 'y = gampdf(x,a,b)'], seealso: ['GammaDistribution', 'pdf', 'gamcdf', 'gaminv', 'gamstat'], description: ['y = gampdf(x,a) returns the probability density function (pdf) of the standard gamma distribution with the shape parameter a, evaluated at the values in x.', 'y = gampdf(x,a,b) returns the pdf of the gamma distribution with the shape parameter a and the scale parameter b, evaluated at the values in x.'] },
    exppdf: { summary: 'Returns the probability density function (pdf) of the standard exponential distribution, evaluated at the values in x.', syntax: ['y = exppdf(x)', 'y = exppdf(x,mu)'], seealso: ['ExponentialDistribution', 'pdf', 'expcdf', 'expinv', 'expstat'], description: ['y = exppdf(x) returns the probability density function (pdf) of the standard exponential distribution, evaluated at the values in x.', 'y = exppdf(x,mu) returns the pdf of the exponential distribution with mean mu, evaluated at the values in x.'] },
    betapdf: { summary: 'Returns the probability density function (pdf) of the beta distribution at each of the values in x using the corresponding parameters in a and b.', syntax: ['y = betapdf(x,a,b)'], seealso: ['pdf', 'betafit', 'betainv', 'betastat', 'betalike'], description: ['y = betapdf(x,a,b) returns the probability density function (pdf) of the beta distribution at each of the values in x using the corresponding parameters in a and b. Values in x must be between [0,1].'] },
    fpdf: { summary: 'Returns the probability density function (pdf) of the F distribution with the numerator degrees of freedom nu1 and denominator degrees of freedom nu2, evaluated at the values in x', syntax: ['p = fpdf(x,nu1,nu2)'], seealso: ['pdf', 'fcdf', 'finv', 'fstat', 'frnd'], description: ['p = fpdf(x,nu1,nu2) returns the probability density function (pdf) of the _F_ distribution with the numerator degrees of freedom nu1 and denominator degrees of freedom nu2, evaluated at the values in x.'] },
    unifpdf: { summary: 'Returns the probability density function (pdf) of the standard uniform distribution, evaluated at the values in x.', syntax: ['y = unifpdf(x)', 'y = unifpdf(x,a,b)'], seealso: ['UniformDistribution', 'pdf', 'unifcdf', 'unifinv', 'unifstat'], description: ['y = unifpdf(x) returns the probability density function (pdf) of the standard uniform distribution, evaluated at the values in x.', 'y = unifpdf(x,a,b) returns the pdf of the continuous uniform distribution on the interval [a, b], evaluated at the values in x.'] },
    lognpdf: { summary: 'Returns the probability density function (pdf) of the standard lognormal distribution, evaluated at the values in x.', syntax: ['y = lognpdf(x)', 'y = lognpdf(x,mu)', 'y = lognpdf(x,mu,sigma)'], seealso: ['pdf', 'logncdf', 'logninv', 'lognstat', 'lognfit'], description: ['y = lognpdf(x) returns the probability density function (pdf) of the standard lognormal distribution, evaluated at the values in x. In the standard lognormal distribution, the mean and standard deviation of logarithmic values are 0 and 1, respectively.', 'y = lognpdf(x,mu) returns the pdf of the lognormal distribution with the distribution parameters mu (mean of logarithmic values) and 1 (standard deviation of logarithmic values), evaluated at the values in x.', 'y = lognpdf(x,mu,sigma) returns the pdf of the lognormal distribution with the distribution parameters mu (mean of logarithmic values) and sigma (standard deviation of logarithmic values), evaluated at the values in x.'] },
    binopdf: { summary: 'Computes the binomial probability density function at each of the values in x using the corresponding number of trials in n and probability of success for each trial in p.', syntax: ['y = binopdf(x,n,p)'], seealso: ['pdf', 'binoinv', 'binocdf', 'binofit', 'binostat'], description: ['y = binopdf(x,n,p) computes the binomial probability density function at each of the values in x using the corresponding number of trials in n and probability of success for each trial in p.', 'x, n, and p can be vectors, matrices, or multidimensional arrays of the same size. Alternatively, one or more arguments can be scalars. The binopdf function expands scalar inputs to constant arrays with the same dimensions as the other inputs.'] },
    poisspdf: { summary: 'Computes the Poisson probability density function at each of the values in x using the rate parameters in lambda.', syntax: ['y = poisspdf(x,lambda)'], seealso: ['pdf', 'poisscdf', 'poissinv', 'poisstat', 'poissfit'], description: ['y = poisspdf(x,lambda) computes the Poisson probability density function at each of the values in x using the rate parameters in lambda.', 'x and lambda can be scalars, vectors, matrices, or multidimensional arrays that all have the same size. If only one argument is a scalar, poisspdf expands it to a constant array with the same dimensions as the other argument.'] },
    geopdf: { summary: 'Returns the probability density function (pdf) of the geometric distribution, evaluated at each value in x using the corresponding probabilities in p.', syntax: ['y = geopdf(x,p)'], seealso: ['geocdf', 'geoinv', 'geostat', 'geornd', 'pdf'], description: ['y = geopdf(x,p) returns the probability density function (pdf) of the geometric distribution, evaluated at each value in x using the corresponding probabilities in p. The parameter p is the probability of success in any given trial, and x is the number of failures before the first success.'] },
    wblpdf: { summary: 'Returns the probability density function (pdf) of the Weibull distribution with unit parameters, evaluated at the values in x.', syntax: ['y = wblpdf(x)', 'y = wblpdf(x,a)', 'y = wblpdf(x,a,b)'], seealso: ['WeibullDistribution', 'pdf', 'wblcdf', 'wblstat', 'wblfit'], description: ['y = wblpdf(x) returns the probability density function (pdf) of the Weibull distribution with unit parameters, evaluated at the values in x.', 'y = wblpdf(x,a) returns the pdf of the Weibull distribution with scale parameter a and unit shape, evaluated at the values in x. This is equivalent to the pdf of the exponential distribution.', 'y = wblpdf(x,a,b) returns the pdf of the Weibull distribution with scale parameter a and shape parameter b, evaluated at the values in x.'] },
    raylpdf: { summary: 'Returns the Rayleigh probability density function (pdf) with the scale parameter b, evaluated at the values in x.', syntax: ['p = raylpdf(x,b)'], seealso: ['pdf', 'raylcdf', 'raylinv', 'raylstat', 'raylfit'], description: ['p = raylpdf(x,b) returns the Rayleigh probability density function (pdf) with the scale parameter b, evaluated at the values in x.'] },
    normstat: { summary: 'Returns the mean and variance of the normal distribution with mean mu and standard deviation sigma.', syntax: ['[m,v] = normstat(mu,sigma)'], seealso: ['normpdf', 'normcdf', 'normrnd', 'NormalDistribution', 'mean'], description: ['[m,v] = normstat(mu,sigma) returns the mean and variance of the normal distribution with mean mu and standard deviation sigma.', 'The mean of the normal distribution with parameters µ and σ is µ, and the variance is σ2.'] },
    unifstat: { summary: 'Returns the element-wise mean and variance of the continuous uniform distribution defined by the lower endpoint (minimum) a and upper endpoint (maximum) b.', syntax: ['[m,v] = unifstat(a,b)'], seealso: ['unifpdf', 'unifcdf', 'unifinv', 'unifit', 'unifrnd'], description: ['[m,v] = unifstat(a,b) returns the element-wise mean and variance of the continuous uniform distribution defined by the lower endpoint (minimum) a and upper endpoint (maximum) b. The endpoints a and b can be scalars, vectors, or multidimensional arrays.'] },
    tstat: "Student's t mean and variance", fstat: { summary: 'F mean and variance', syntax: [], description: ['m = fstat(nu1,nu2) returns the mean of the _F_ distribution with nu1 numerator degrees of freedom and nu2 denominator degrees of freedom.', '[m,v] = fstat(nu1,nu2) also returns the variance for the distribution.'] }, lognstat: { summary: 'Lognormal mean and variance', syntax: [], description: ['[m,v] = lognstat(mu,sigma) returns the mean and variance of the lognormal distribution with the distribution parameters mu (mean of logarithmic values) and sigma (standard deviation of logarithmic values).'] }, geostat: { summary: 'Geometric mean and variance', syntax: [], description: ['[m,v] = geostat(p) returns the mean m and variance v of a geometric distribution with the corresponding probability parameter in p. For more information, see Geometric Distribution Mean and Variance.'] },
    raylstat: { summary: 'Returns the mean for the Rayleigh distribution with the scale parameter b.', syntax: ['m = raylstat(b)', '[m,v] = raylstat(b)'], seealso: ['raylpdf', 'raylcdf', 'raylinv', 'raylfit', 'raylrnd'], description: ['m = raylstat(b) returns the mean for the Rayleigh distribution with the scale parameter b.', '[m,v] = raylstat(b) also returns the variance for the distribution.'] },
    evpdf: { summary: 'Returns the probability density function (pdf) of the type 1 extreme value distribution (also known as the Gumbel distribution) with a location parameter equal to 0 and a scale pa', syntax: ['p = evpdf(x)', 'p = evpdf(x,mu,sigma)'], seealso: ['pdf', 'evcdf', 'evinv', 'evstat', 'evfit'], description: ['p = evpdf(x) returns the probability density function (pdf) of the type 1 extreme value distribution (also known as the Gumbel distribution) with a location parameter equal to 0 and a scale parameter equal to 1, evaluated at the values in x. The software returns the pdf for the minimum case. To model the maximum case, call evpdf using the negative of the original values in x. For more information, see Extreme Value Distribution.', 'p = evpdf(x,mu,sigma) returns the pdf with the location parameters mu and scale parameters sigma, evaluated at the values in x.'] },
    gevpdf: { summary: 'Returns the probability density function (pdf) of the generalized extreme value (GEV) distribution with a shape parameter equal to 0, scale parameter equal to 1, and location para', syntax: ['p = gevpdf(x)', 'p = gevpdf(x,k,sigma,mu)'], seealso: ['pdf', 'gevcdf', 'gevinv', 'gevstat', 'gevfit'], description: ['p = gevpdf(x) returns the probability density function (pdf) of the generalized extreme value (GEV) distribution with a shape parameter equal to 0, scale parameter equal to 1, and location parameter equal to 0, evaluated at the values in x.', 'p = gevpdf(x,k,sigma,mu) returns the pdf with the shape parameter k, scale parameter sigma, and location parameter mu, evaluated at the values in x.', 'When k < 0, the GEV distribution is the type III extreme value distribution. When k > 0, the GEV distribution is the type II (Frechet) extreme value distribution. If w has a Weibull distribution, then –w has a type III extreme value distribution and 1/w has a type II extreme value distribution. In the limiting case as k approaches 0, the GEV distribution is the mirror image of the type I (Gumbel) extreme value distribution. For more information, see Generalized Extreme Value Distribution.', 'The mean of the GEV distribution is not finite when k ≥ 1, and the variance is not finite when k ≥ 1/2. The GEV distribution has positive density only for values of x such that k*(x – mu)/sigma > –1. For more information, see Generalized Extreme Value Distribution.'] },
    gppdf: { summary: 'Returns the probability density function (pdf) of the generalized Pareto (GP) distribution with a shape parameter equal to 0, a scale parameter equal to 1, and a threshold (locati', syntax: ['p = gppdf(x)', 'p = gppdf(x,k,sigma,theta)'], seealso: ['pdf', 'gpcdf', 'gpinv', 'gpstat', 'gpfit'], description: ['p = gppdf(x) returns the probability density function (pdf) of the generalized Pareto (GP) distribution with a shape parameter equal to 0, a scale parameter equal to 1, and a threshold (location) parameter equal to 0, evaluated at the values in x. For more information, see Generalized Pareto Distribution.', 'p = gppdf(x,k,sigma,theta) returns the pdf using the shape parameter k, scale parameter sigma, and location parameter theta, evaluated at the values in x.'] },
    nbinpdf: { summary: 'Returns the negative binomial probability density function (pdf), evaluated at the values in x, using the corresponding number of successes r and the probability of success in a s', syntax: ['y = nbinpdf(x,r,p)'], seealso: ['pdf', 'nbincdf', 'nbininv', 'nbinstat', 'nbinfit'], description: ['y = nbinpdf(x,r,p) returns the negative binomial probability density function (pdf), evaluated at the values in x, using the corresponding number of successes r and the probability of success in a single trial p.'] },
    hygepdf: { summary: 'Returns the probability density function (pdf) of the hypergeometric distribution, evaluated at the values in x, using the corresponding size of the population m, the number of it', syntax: ['p = hygepdf(x,m,k,n)'], seealso: ['pdf', 'hygecdf', 'hygeinv', 'hygestat', 'hygernd'], description: ['p = hygepdf(x,m,k,n) returns the probability density function (pdf) of the hypergeometric distribution, evaluated at the values in x, using the corresponding size of the population m, the number of items with the intended characteristic in the population k, and the number of items drawn n.'] },
    ncx2pdf: { summary: 'Returns the noncentral chi-square probability density function (pdf) with nu degrees of freedom and the noncentrality parameter delta, evaluated at the values in x.', syntax: ['p = ncx2pdf(x,nu,delta)'], seealso: ['pdf', 'ncx2cdf', 'ncx2inv', 'ncx2stat', 'ncx2rnd'], description: ['p = ncx2pdf(x,nu,delta) returns the noncentral chi-square probability density function (pdf) with nu degrees of freedom and the noncentrality parameter delta, evaluated at the values in x.'] },
    ncfpdf: { summary: 'Returns the noncentral F probability density function (pdf) with nu1 numerator degrees of freedom, nu2 denominator degrees of freedom, and the noncentrality parameter delta, evalu', syntax: ['p = ncfpdf(x,nu1,nu2,delta)'], seealso: ['pdf', 'ncfcdf', 'ncfinv', 'ncfstat', 'ncfrnd'], description: ['p = ncfpdf(x,nu1,nu2,delta) returns the noncentral _F_ probability density function (pdf) with nu1 numerator degrees of freedom, nu2 denominator degrees of freedom, and the noncentrality parameter delta, evaluated at the values in x.'] },
    nctpdf: { summary: 'Returns the noncentral t probability density function (pdf) with nu degrees of freedom and the noncentrality parameter delta, evaluated at the values in x.', syntax: ['p = nctpdf(x,nu,delta)'], seealso: ['pdf', 'nctcdf', 'nctinv', 'nctstat', 'nctrnd'], description: ['p = nctpdf(x,nu,delta) returns the noncentral _t_ probability density function (pdf) with nu degrees of freedom and the noncentrality parameter delta, evaluated at the values in x.'] },
    expfit: { summary: 'Returns the maximum likelihood estimates (MLEs) of the mean parameter mu of the exponential distribution, given the sample data in x.', syntax: ['pHat = expfit(x)', '[pHat,pCI] = expfit(x)', '[pHat,pCI] = expfit(x,alpha)', '[ ___ ] = expfit(x,alpha,censoring)'], seealso: ['mle', 'explike', 'exppdf', 'expcdf', 'expinv'], description: ['pHat = expfit(x) returns the maximum likelihood estimates (MLEs) of the mean parameter mu of the exponential distribution, given the sample data in x.', '[pHat,pCI] = expfit(x) also returns the 95% confidence intervals for the parameter estimates.', '[pHat,pCI] = expfit(x,alpha) specifies the confidence level for the confidence intervals to be 100(1 – alpha)%.', '[___] = expfit(x,alpha,censoring) accepts a Boolean vector, censoring, of the same size as x, containing the value 1 for observations that are right-censored and 0 for observations that are observed exactly.', '[___] = expfit(x,alpha,censoring,freq) specifies the frequency (or weights) of the observations.'] },
    binofit: { summary: 'Returns the maximum likelihood estimates (MLEs) of the probability of success in a given binomial trial based on the number of successes r observed in n independent trials.', syntax: ['pHat = binofit(r,n)', '[pHat,pCI] = binofit(r,n)', '[pHat,pCI] = binofit(r,n,alpha)'], seealso: ['mle', 'binopdf', 'binocdf', 'binoinv', 'binostat'], description: ['pHat = binofit(r,n) returns the maximum likelihood estimates (MLEs) of the probability of success in a given binomial trial based on the number of successes r observed in n independent trials.', 'Note', 'When r is a vector, binofit, unlike most distribution fitting functions, treats r as a collection of measurements from separate samples. To treat r as a single sample and compute a single parameter estimate for it, use binofit(sum(r),sum(n)) when n is a vector, or binofit(sum(r),n*length(r)) when n is a scalar.', '[pHat,pCI] = binofit(r,n) also returns the 95% confidence intervals for the parameter estimates.', '[pHat,pCI] = binofit(r,n,alpha) specifies the confidence level for the confidence intervals to be 100(1 – alpha)%.'] },
    lognfit: { summary: 'Returns unbiased estimates of lognormal distribution parameters, given the sample data in x.', syntax: ['pHat = lognfit(x)', '[pHat,pCI] = lognfit(x)', '[pHat,pCI] = lognfit(x,alpha)', '[ ___ ] = lognfit(x,alpha,censoring)'], seealso: ['mle', 'lognlike', 'lognpdf', 'logncdf', 'logninv'], description: ['pHat = lognfit(x) returns unbiased estimates of lognormal distribution parameters, given the sample data in x. pHat(1) and pHat(2) are the mean and standard deviation of logarithmic values, respectively.', '[pHat,pCI] = lognfit(x) also returns 95% confidence intervals for the parameter estimates.', '[pHat,pCI] = lognfit(x,alpha) specifies the confidence level for the confidence intervals to be 100(1–alpha)%.', '[___] = lognfit(x,alpha,censoring) specifies whether each value in x is right-censored or not. Use the logical vector censoring in which 1 indicates observations that are right-censored and 0 indicates observations that are fully observed. With censoring, the phat values are the maximum likelihood estimates (MLEs).', '[___] = lognfit(x,alpha,censoring,freq) specifies the frequency (or weights) of the observations.'] },
    mvnpdf: { summary: 'Returns an n-by-1 vector y containing the probability density function (pdf) values for the d-dimensional multivariate normal distribution with zero mean and identity covariance m', syntax: ['y = mvnpdf(X)', 'y = mvnpdf(X,mu)', 'y = mvnpdf(X,mu,Sigma)'], seealso: ['mvncdf', 'mvnrnd', 'normpdf'], description: ['y = mvnpdf(X) returns an _n_ -by-1 vector y containing the probability density function (pdf) values for the _d_ -dimensional multivariate normal distribution with zero mean and identity covariance matrix, evaluated at each row of the _n_ -by-_d_ matrix X. For more information, see Multivariate Normal Distribution.', 'y = mvnpdf(X,mu) returns pdf values of points in X, where mu determines the mean of each associated multivariate normal distribution.', 'y = mvnpdf(X,mu,Sigma) returns pdf values of points in X, where Sigma determines the covariance of each associated multivariate normal distribution.', 'Specify [] for mu to use its default value of zero when you want to specify only Sigma.'] },
    ecdf: { summary: 'Returns the empirical cumulative distribution function f, evaluated at x, using the data in y.', syntax: ['ecdf( ___ )', 'ecdf(ax, ___ )'], seealso: ['cdfplot', 'ecdfhist', 'EmpiricalDistribution'], description: ['[f,x] = ecdf(y) returns the empirical cumulative distribution function f, evaluated at x, using the data in y.', '[f,x] = ecdf(y,Name,Value) specifies additional options using one or more name-value arguments. For example, \'Function\',\'survivor\' specifies the type of function for f as a survivor function.', '[f,x,flo,fup] = ecdf(___) also returns the lower and upper confidence bounds for the evaluated function values, using any of the input argument combinations in the previous syntaxes. This syntax is not valid for interval-censored data.', 'ecdf(___) produces a stairstep graph of the evaluated function. The function visualizes interval estimates for interval-censored data using shaded rectangles. You can specify \'Bounds\',\'on\' to include the confidence bounds in the graph for fully observed, left-censored, right-censored, and double- censored data.', 'ecdf(ax,___) plots on the axes specified by ax instead of the current axes (gca).'] },
    betafit: { summary: 'Returns the maximum likelihood estimates (MLEs) of the beta distribution parameters a and b, given the data in x.', syntax: ['pHat= betafit(x)', '[pHat,pCI] = betafit(x)', '[pHat,pCI] = betafit(x,alpha)'], seealso: ['mle', 'betapdf', 'betainv', 'betastat', 'betalike'], description: ['pHat= betafit(x) returns the maximum likelihood estimates (MLEs) of the beta distribution parameters _a_ and _b_ , given the data in x. For more information, see Beta Distribution.', '[pHat,pCI] = betafit(x) also returns the 95% confidence intervals for the parameter estimates.', '[pHat,pCI] = betafit(x,alpha) specifies the confidence level for the confidence intervals to be 100(1 – alpha)%.'] },
    nanmean: { summary: 'Mean ignoring NaN values', syntax: ['m = nanmean(x)', 'm = nanmean(x,dim)'], seealso: ['mean', 'nanmedian', 'nanstd'] },
    nanmedian: { summary: 'Median ignoring NaN values', syntax: ['m = nanmedian(x)', 'm = nanmedian(x,dim)'], seealso: ['median', 'nanmean'] },
    range: { summary: 'Returns the difference between the maximum and minimum values of sample data in X.', syntax: ['y = range(X)', 'y = range(X,\'all\')', 'y = range(X,dim)', 'y = range(X,vecdim)'], seealso: ['std', 'iqr', 'mad'], description: ['y = range(X) returns the difference between the maximum and minimum values of sample data in X.', '* If X is a vector, then range(X) is the range of the values in X.', '* If X is a matrix, then range(X) is a row vector containing the range of each column in X.', '* If X is a multidimensional array, then range operates along the first nonsingleton dimension of X, treating the values as vectors. The size of this dimension becomes 1 while the sizes of all other dimensions remain the same. If X is an empty array with first dimension 0, then range(X) returns an empty array with the same size as X.', 'y = range(X,\'all\') returns the range of all elements in X.'] },
    pdist: { summary: 'Returns the Euclidean distance between pairs of observations in X.', syntax: ['D = pdist(X)', 'D = pdist(X,Distance)', 'D = pdist(X,Distance,DistParameter)', 'D = pdist(X,Distance,CacheSize=cache)'], seealso: ['cluster', 'clusterdata', 'cmdscale', 'cophenet', 'dendrogram'], description: ['D = pdist(X) returns the Euclidean distance between pairs of observations in X.', 'D = pdist(X,Distance) returns the distance using the method specified by Distance.', 'D = pdist(X,Distance,DistParameter) returns the distance using the method specified by Distance and DistParameter. You can specify DistParameter only when Distance is "seuclidean", "minkowski", or "mahalanobis".', 'D = pdist(X,Distance,CacheSize=cache) or D = pdist(X,Distance,DistParameter,CacheSize=cache) uses a cache of size cache megabytes to accelerate the computation of Euclidean distances. This argument applies only when Distance is "fasteuclidean", "fastsquaredeuclidean", or "fastseuclidean".'] },
    tiedrank: { summary: 'Returns the rank of each value in X.', syntax: ['[R,tieadj] = tiedrank(X)', '[R,tieadj] = tiedrank(X,1)', '[R,tieadj] = tiedrank(X,0,1)'], seealso: ['ansaribradley', 'corr', 'partialcorr', 'ranksum', 'signrank'], description: ['[R,tieadj] = tiedrank(X) returns the rank of each value in X. The function also returns an adjustment for ties between values that is used by the signrank and ranksum functions, and in the computation of the Spearman distance metric (see Distance Metrics). If any values in X are tied, tiedrank returns their average rank.', '[R,tieadj] = tiedrank(X,1) returns the rank of the each value in X and adjustments for ties that are used in the computation of Kendall\'s Tau Coefficient.', '[R,tieadj] = tiedrank(X,0,1) returns the rank of each value in X and adjustments for ties in X that are used in the Ansari-Bradley Test. The function computes the ranks from each end, so that the smallest and largest values are rank 1, the next smallest and largest values are rank 2, and so on.'] },
    tabulate: { summary: 'Displays a frequency table of the data in the vector x.', syntax: ['tabulate(x)', 'tbl = tabulate(x)'], seealso: ['pareto', 'histogram', 'bar', 'grpstats', 'groupcounts'], description: ['tabulate(x) displays a frequency table of the data in the vector x. For each unique value in x, the tabulate function shows the number of instances and percentage of that value in x. See tbl.', 'tbl = tabulate(x) returns the frequency table tbl as a numeric matrix when x is numeric and as a cell array otherwise.'] },
    geoinv: { summary: 'Returns the inverse cumulative distribution function (icdf) of the geometric distribution at each value in y using the corresponding probabilities in p.', syntax: ['x = geoinv(y,p)'], seealso: ['geocdf', 'geopdf', 'geostat', 'geornd', 'icdf'], description: ['x = geoinv(y,p) returns the inverse cumulative distribution function (icdf) of the geometric distribution at each value in y using the corresponding probabilities in p.'] },
    ff2n: { summary: 'Returns a 2n-by-n numeric matrix dFF2 containing the treatments of a full factorial design for n two-level factors.', syntax: ['dFF2 = ff2n(n)'], seealso: ['fullfact', 'fracfact', 'fracfactgen', 'hadamard'], description: ['dFF2 = ff2n(n) returns a _2n_-by-n numeric matrix dFF2 containing the treatments of a full factorial design for n two-level factors. Each row of dFF2 corresponds to a single treatment (combination of the factor levels). Each column of dFF2 contains the treatment values for a single factor, with values of 0 and 1 for the two levels.'] },
    combnk: { summary: 'All combinations of n elements taken k at a time', syntax: ['C = combnk(v,k)'], seealso: ['nchoosek', 'perms'] },
    explike: { summary: 'Returns the exponential negative loglikelihood of the parameter mu, given the sample data x.', syntax: ['nlogL = explike(mu,x)', 'nlogL = explike(mu,x,censoring)', 'nlogL = explike(mu,x,censoring,freq)', '[nlogL,aVar] = explike( ___ )'], seealso: ['expcdf', 'exppdf', 'expstat', 'expfit', 'expinv'], description: ['nlogL = explike(mu,x) returns the exponential negative loglikelihood of the parameter mu, given the sample data x.', 'nlogL = explike(mu,x,censoring) specifies whether each value in x is right-censored or not. Use the logical vector censoring to specify the value 1 for observations that are right-censored and 0 for observations that are fully observed.', 'nlogL = explike(mu,x,censoring,freq) specifies the frequency (or weights) of the observations. To specify freq without specifying censoring, you can pass [] for censoring.', '[nlogL,aVar] = explike(___) also returns the inverse of the Fisher information aVar, a scalar, using any of the input argument combinations in the previous syntaxes. If the input parameter value in mu is the maximum likelihood estimate (MLE), aVar is its asymptotic variance. aVar is based on the observed Fisher information, not the expected information.'] },
    unidpdf: { summary: 'Returns the probability density function (pdf) of the discrete uniform distribution with the maximum value n, evaluated at the values in x.', syntax: ['p = unidpdf(x,n)'], seealso: ['pdf', 'unidcdf', 'unidinv', 'unidstat', 'unidrnd'], description: ['p = unidpdf(x,n) returns the probability density function (pdf) of the discrete uniform distribution with the maximum value n, evaluated at the values in x.'] },
    unidinv: { summary: 'Returns the inverse cumulative distribution function (icdf) of the discrete uniform distribution with the maximum values in n, evaluated at the probability values in p.', syntax: ['x = unidinv(p,n)'], seealso: ['icdf', 'unidcdf', 'unidpdf', 'unidstat', 'unidrnd'], description: ['x = unidinv(p,n) returns the inverse cumulative distribution function (icdf) of the discrete uniform distribution with the maximum values in n, evaluated at the probability values in p.'] },
    regress: { summary: 'Returns a vector b of coefficient estimates for a multiple linear regression of the responses in vector y on the predictors in matrix X.', syntax: ['b = regress(y,X)', '[b,bint] = regress(y,X)', '[b,bint,r] = regress(y,X)', '[b,bint,r,rint] = regress(y,X)'], seealso: ['LinearModel', 'fitlm', 'stepwiselm', 'mvregress', 'rcoplot'], description: ['b = regress(y,X) returns a vector b of coefficient estimates for a multiple linear regression of the responses in vector y on the predictors in matrix X. To compute coefficient estimates for a model with a constant term (intercept), include a column of ones in the matrix X.', '[b,bint] = regress(y,X) also returns a matrix bint of 95% confidence intervals for the coefficient estimates.', '[b,bint,r] = regress(y,X) also returns an additional vector r of residuals.', '[b,bint,r,rint] = regress(y,X) also returns a matrix rint of intervals that can be used to diagnose outliers.', '[b,bint,r,rint,stats] = regress(y,X) also returns a vector stats that contains the _R 2_ statistic, the _F_ -statistic and its _p_ -value, and an estimate of the error variance. The matrix X must include a column of ones for the software to compute the model statistics correctly.'] },
    glmfit: { summary: 'Returns a vector b of coefficient estimates for a generalized linear regression model of the responses in y on the predictors in X, using the distribution distr.', syntax: ['b = glmfit(X,y,distr)', 'b = glmfit(X,y,distr,Name,Value)', '[b,dev] = glmfit( ___ )', '[b,dev,stats] = glmfit( ___ )'], seealso: ['glmval', 'regress', 'regstats', 'GeneralizedLinearModel', 'fitglm'], description: ['b = glmfit(X,y,distr) returns a vector b of coefficient estimates for a generalized linear regression model of the responses in y on the predictors in X, using the distribution distr.', 'b = glmfit(X,y,distr,Name,Value) specifies additional options using one or more name-value arguments. For example, you can specify \'Constant\',\'off\' to omit the constant term from the model.', '[b,dev] = glmfit(___) also returns the value dev, the deviance of the fit.', '[b,dev,stats] = glmfit(___) also returns the model statistics stats.'] },
    makedist: { summary: 'Creates a probability distribution object for the distribution distname, using the default parameter values.', syntax: ['pd = makedist(distname)', 'pd = makedist(distname,Name,Value)', 'list = makedist', 'makedist -reset'], seealso: ['fitdist'], description: ['pd = makedist(distname) creates a probability distribution object for the distribution distname, using the default parameter values.', 'pd = makedist(distname,Name,Value) creates a probability distribution object with one or more distribution parameter values specified by name-value pair arguments.', 'list = makedist returns a cell array list containing a list of the probability distributions that makedist can create.', 'makedist -reset resets the list of distributions by searching the path for files contained in a namespace named prob and implementing classes derived from ProbabilityDistribution. Use this syntax after you define a custom distribution function. For details, see Define Custom Distributions Using the Distribution Fitter App.'] },
    confusionmat: { summary: 'Returns the confusion matrix C determined by the known and predicted groups in group and grouphat, respectively.', syntax: ['C = confusionmat(group,grouphat)', 'C = confusionmat(group,grouphat,\'Order\',grouporder)', '[C,order] = confusionmat( ___ )'], seealso: ['categories', 'crosstab', 'confusionchart'], description: ['C = confusionmat(group,grouphat) returns the confusion matrix C determined by the known and predicted groups in group and grouphat, respectively.', 'C = confusionmat(group,grouphat,\'Order\',grouporder) uses grouporder to order the rows and columns of C.', '[C,order] = confusionmat(___) also returns the order of the rows and columns of C in the variable order using any of the input arguments in previous syntaxes.'] },
    mahal: { summary: 'Returns the squared Mahalanobis distance of each observation in Y to the reference samples in X.', syntax: ['d2 = mahal(Y,X)'], seealso: ['pdist', 'pdist2', 'mahal', 'mahal', 'robustcov'], description: ['d2 = mahal(Y,X) returns the squared Mahalanobis distance of each observation in Y to the reference samples in X.'] },
    pcares: { summary: 'Returns the residuals from a principal components analysis of X using ndim principal components.', syntax: ['residuals = pcares(X,ndim)', '[residuals,reconstructed] = pcares(X,ndim)'], seealso: ['pca', 'pcacov', 'ppca', 'biplot'], description: ['residuals = pcares(X,NumComponents) returns the residuals obtained by retaining NumComponents principal components of the data matrix X.', 'pcares does not normalize the columns of X. You can perform principal component analysis based on standardized variables using pcares(zscore(X),NumComponents). To perform principal component analysis directly on a covariance or correlation matrix, but without computing residuals, use pcacov.', '[residuals,reconstructed] = pcares(X) additionally returns an approximation to X obtained by retaining its first NumComponents principal components. reconstructed is equal to X minus residuals.'] },
    ksdensity: { summary: 'Computes a probability density estimate of the sample in data vector x.', syntax: ['[f,xi] = ksdensity(x)', 'f = ksdensity(x,pts)', '[f,xi] = ksdensity(x,Name,Value)'], seealso: ['histogram', 'ecdf', 'fitdist'], description: ['[f,xi] = ksdensity(x) returns a probability density estimate, f, for the sample data in the vector or two-column matrix x. The estimate is based on a normal kernel function, and is evaluated at equally-spaced points, xi, that cover the range of the data in x. ksdensity estimates the density at 100 points for univariate data, or 900 points for bivariate data.', 'ksdensity works best with continuously distributed samples.', '[f,xi] = ksdensity(x,pts) specifies points (pts) to evaluate f. Here, xi and pts contain identical values.', '[f,xi] = ksdensity(___,Name,Value) uses additional options specified by one or more name-value pair arguments in addition to any of the input arguments in the previous syntaxes. For example, you can define the function type ksdensity evaluates, such as probability density, cumulative probability, survivor function, and so on. Or you can specify the bandwidth of the smoothing window.', '[f,xi,bw] = ksdensity(___) also returns the bandwidth of the kernel smoothing window, bw. The default bandwidth is the optimal for normal densities.'] },
    nlinfit: { summary: 'Estimates coefficients of a nonlinear regression function using least squares.', syntax: ['beta = nlinfit(X,y,modelfun,beta0)', '[beta,R] = nlinfit(X,y,modelfun,beta0)', '[beta,R,J,CovB,MSE] = nlinfit(X,y,modelfun,beta0)'], seealso: ['lsqcurvefit', 'nlpredci', 'nlintool', 'regress', 'robustfit'], description: ['beta = nlinfit(X,Y,modelfun,beta0) returns a vector of estimated coefficients for the nonlinear regression of the responses in Y on the predictors in X using the model specified by modelfun. The coefficients are estimated using iterative least squares estimation, with initial values specified by beta0.', 'beta = nlinfit(X,Y,modelfun,beta0,options) fits the nonlinear regression using the algorithm control parameters in the structure options. You can return any of the output arguments in the previous syntaxes.', 'beta = nlinfit(___,Name=Value)specifies options using one or more name- value arguments in addition to any of the input argument combinations in the previous syntaxes. For example, you can set observation weights and specify a nonconstant error model.', '[beta,R,J,CovB,MSE,ErrorModelInfo] = nlinfit(___) additionally returns the residuals, R, the Jacobian of modelfun, J, the estimated variance-covariance matrix for the estimated coefficients, CovB, an estimate of the variance of the error term, MSE, and a structure containing details about the error model, ErrorModelInfo.'] },
    procrustes: { summary: 'Compares two shapes using a Procrustes analysis.', syntax: ['d = procrustes(X,Y)', '[d,Z] = procrustes(X,Y)', '[d,Z,transform] = procrustes(X,Y)'], seealso: ['cmdscale'], description: ['d = procrustes(X,Y) returns the squared Procrustes Distance between the shapes of X and Y, which are represented by configurations of landmark points.', 'd = procrustes(X,Y,Name,Value) specifies additional options using one or more name-value arguments. For example, you can restrict the Procrustes transformation by disabling reflection and scaling.', '[d,Z] = procrustes(___) also returns Z, the shape resulting from performing the Procrustes transformation on Y, using any of the input argument combinations in the previous syntaxes', '[d,Z,transform] = procrustes(___) also returns the Procrustes transformation.'] },
    canoncorr: { summary: 'Computes sample canonical correlations between the columns of X and Y.', syntax: ['[A,B,r] = canoncorr(X,Y)', '[A,B,r,U,V] = canoncorr(X,Y)'], seealso: ['corr', 'partialcorr', 'manova1'], description: ['[A,B] = canoncorr(X,Y) computes the sample canonical coefficients for the data matrices X and Y.', '[A,B,r] = canoncorr(X,Y) also returns r, a vector of the sample canonical correlations.', '[A,B,r,U,V] = canoncorr(X,Y) also returns U and V, matrices of the canonical scores for X and Y, respectively.', '[A,B,r,U,V,stats] = canoncorr(X,Y) also returns stats, a structure containing information related to testing the sequence of hypotheses that the remaining correlations are all zero.'] },
    nnmf: { summary: 'Factors matrix A into nonneg matrices W (n-by-k) and H (k-by-m) by alternating least squares.', syntax: ['[W,H] = nnmf(A,k)', '[W,H,D] = nnmf(A,k)'], seealso: ['pca', 'svd', 'factoran'], description: ['[W,H] = nnmf(A,k) factors the _n_ -by-_m_ matrix A into nonnegative factors W (_n_ -by-k) and H (k-by-_m_). The factorization is not exact; WH is a lower-rank approximation to A. The factors W and H minimize the root mean square residual D between A and WH.', 'D = norm(A - WH,\'fro\')/sqrt(nm)', 'The factorization uses an iterative algorithm starting with random initial values for W and H. Because the root mean square residual D might have local minima, repeated factorizations might yield different W and H. Sometimes the algorithm converges to a solution of lower rank than _k_ , which can indicate that the result is not optimal.', '[W,H] = nnmf(A,k,Name,Value) modifies the factorization using one or more name-value pair arguments. For example, you can request repeated factorizations by setting \'Replicates\' to an integer value greater than 1.', '[W,H,D] = nnmf(___) also returns the root mean square residual D using any of the input argument combinations in the previous syntaxes.'] },
  };
